/**
 * Corgi Dashboard — Web Page Viewer Panel
 *
 * Displays extracted markdown content from web_fetch results in a side panel.
 * Renders using the shared MarkdownRenderer with truncation for long content.
 */
import React, { useState } from 'react';
import { ExternalLink } from 'lucide-react';
import { SidePanel } from './SidePanel';
import { useContentPanel, type WebPageContent } from './ContentPanelManager';
import { Skeleton } from '../../theme/skeleton';
import MarkdownRenderer from '../chat/MarkdownRenderer';

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const TRUNCATION_LIMIT = 5000;

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const WebPagePanel: React.FC = () => {
  const { panelType, panelContent, closePanel } = useContentPanel();
  const [showFull, setShowFull] = useState(false);

  if (panelType !== 'webpage') return null;

  const content = panelContent as WebPageContent | null;
  if (!content) return null;

  const isLong = content.content.length > TRUNCATION_LIMIT;
  const displayContent = isLong && !showFull
    ? content.content.slice(0, TRUNCATION_LIMIT)
    : content.content;

  const headerActions = content.url ? (
    <a
      href={content.url}
      target="_blank"
      rel="noopener noreferrer"
      className="p-1.5 rounded-md transition-colors"
      style={{
        color: 'var(--text-muted)',
        display: 'flex',
        alignItems: 'center',
      }}
      onMouseEnter={(e) => {
        (e.currentTarget as HTMLElement).style.color = 'var(--accent-primary)';
      }}
      onMouseLeave={(e) => {
        (e.currentTarget as HTMLElement).style.color = 'var(--text-muted)';
      }}
      title="Open in new tab"
    >
      <ExternalLink size={14} />
    </a>
  ) : undefined;

  return (
    <SidePanel
      open
      onClose={closePanel}
      title={content.title ?? 'Web Page'}
      headerActions={headerActions}
    >
      {/* Source URL */}
      {content.url && (
        <div
          className="mb-3 px-3 py-2 rounded-md"
          style={{
            background: 'var(--bg-tertiary)',
            fontSize: 'var(--text-xs)',
          }}
        >
          <a
            href={content.url}
            target="_blank"
            rel="noopener noreferrer"
            style={{
              color: 'var(--text-muted)',
              textDecoration: 'none',
              wordBreak: 'break-all',
            }}
            onMouseEnter={(e) => {
              (e.currentTarget as HTMLElement).style.color = 'var(--accent-primary)';
            }}
            onMouseLeave={(e) => {
              (e.currentTarget as HTMLElement).style.color = 'var(--text-muted)';
            }}
          >
            {content.url}
          </a>
        </div>
      )}

      {/* Markdown content */}
      {content.content ? (
        <>
          <MarkdownRenderer content={displayContent} />

          {isLong && !showFull && (
            <div className="mt-4 flex justify-center">
              <button
                onClick={() => setShowFull(true)}
                className="px-4 py-2 rounded-md transition-colors"
                style={{
                  background: 'var(--bg-tertiary)',
                  color: 'var(--accent-primary)',
                  border: '1px solid var(--border-subtle)',
                  cursor: 'pointer',
                  fontSize: 'var(--text-sm)',
                  fontWeight: 'var(--font-medium)',
                }}
                onMouseEnter={(e) => {
                  (e.currentTarget as HTMLElement).style.background = 'var(--bg-secondary)';
                }}
                onMouseLeave={(e) => {
                  (e.currentTarget as HTMLElement).style.background = 'var(--bg-tertiary)';
                }}
              >
                Show full page ({Math.ceil(content.content.length / 1000)}k chars)
              </button>
            </div>
          )}
        </>
      ) : (
        /* Loading state */
        <div className="flex flex-col gap-3">
          <Skeleton variant="text" lines={1} width="60%" />
          <Skeleton variant="text" lines={4} />
          <Skeleton variant="rect" height="6rem" />
          <Skeleton variant="text" lines={3} />
        </div>
      )}
    </SidePanel>
  );
};

/**
 * Inline loading placeholder for web page panels.
 */
export const WebPagePanelLoading: React.FC = () => (
  <div className="flex flex-col gap-3 p-4">
    <Skeleton variant="text" width="40%" />
    <Skeleton variant="text" lines={5} />
    <Skeleton variant="rect" height="4rem" />
  </div>
);

/**
 * Error state for unavailable web content.
 */
export const WebPagePanelError: React.FC<{ url?: string }> = ({ url }) => (
  <div
    className="flex flex-col items-center justify-center gap-3 py-12"
    style={{ color: 'var(--text-muted)' }}
  >
    <div
      style={{
        width: 48,
        height: 48,
        borderRadius: 'var(--radius-full)',
        background: 'var(--bg-tertiary)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
      }}
    >
      <ExternalLink size={20} style={{ color: 'var(--text-muted)' }} />
    </div>
    <p style={{ fontSize: 'var(--text-sm)' }}>Content unavailable</p>
    {url && (
      <a
        href={url}
        target="_blank"
        rel="noopener noreferrer"
        style={{
          fontSize: 'var(--text-xs)',
          color: 'var(--accent-primary)',
          textDecoration: 'underline',
        }}
      >
        Open in browser
      </a>
    )}
  </div>
);

export default WebPagePanel;
